import React from 'react';

interface CartoonSVGProps extends React.SVGProps<SVGSVGElement> {
  children?: React.ReactNode;
  size?: number | string;
  animClass?: string;
}

// Playful, vibrant child-friendly SVG wrapper standardising sizes, colors, and claymorphic 3D rendering
export const CartoonSVG = ({ children, size = 100, animClass = "anim-float", ...props }: CartoonSVGProps) => {
  return (
    <svg 
      xmlns="http://www.w3.org/2000/svg" 
      viewBox="0 0 32 32" 
      fill="none" 
      width={size}
      height={size}
      className={`overflow-visible transition-transform duration-300 hover:scale-108 active:scale-95 active:rotate-1 ${animClass}`}
      style={{ width: size, height: size, display: 'inline-block', cursor: 'pointer' }}
      {...props}
    >
      <defs>
        <filter id="clay-filter" x="-20%" y="-20%" width="140%" height="140%">
          {/* 1. Outer Drop Shadow */}
          <feGaussianBlur in="SourceAlpha" stdDeviation="1.5" result="blur-out" />
          <feOffset in="blur-out" dx="1" dy="1.5" result="offset-out" />
          <feFlood floodColor="#4a5358" floodOpacity="0.1" result="flood-out" />
          <feComposite in="flood-out" in2="offset-out" operator="in" result="shadow-out" />

          {/* 2. Base Graphic */}
          <feMerge result="base">
            <feMergeNode in="shadow-out" />
            <feMergeNode in="SourceGraphic" />
          </feMerge>

          {/* 3. Inner Dark Shadow */}
          <feOffset in="SourceAlpha" dx="-1" dy="-1" result="offset-dark-alpha" />
          <feComposite in="SourceAlpha" in2="offset-dark-alpha" operator="out" result="dark-shape" />
          <feGaussianBlur in="dark-shape" stdDeviation="0.8" result="blur-dark" />
          <feFlood floodColor="#000000" floodOpacity="0.12" result="flood-dark" />
          <feComposite in="flood-dark" in2="blur-dark" operator="in" result="raw-dark" />
          <feComposite in="raw-dark" in2="SourceAlpha" operator="in" result="inner-dark" />

          {/* 4. Inner Light Highlight */}
          <feOffset in="SourceAlpha" dx="1" dy="1" result="offset-light-alpha" />
          <feComposite in="SourceAlpha" in2="offset-light-alpha" operator="out" result="light-shape" />
          <feGaussianBlur in="light-shape" stdDeviation="0.8" result="blur-light" />
          <feFlood floodColor="#ffffff" floodOpacity="0.6" result="flood-light" />
          <feComposite in="flood-light" in2="blur-light" operator="in" result="raw-light" />
          <feComposite in="raw-light" in2="SourceAlpha" operator="in" result="inner-light" />

          {/* 5. Final Assembly */}
          <feMerge>
            <feMergeNode in="base" />
            <feMergeNode in="inner-dark" />
            <feMergeNode in="inner-light" />
          </feMerge>
        </filter>
      </defs>
      <style>{`
        @keyframes float-playful {
          0%, 100% { transform: translateY(0px) rotate(0deg); }
          50% { transform: translateY(-3px) rotate(1deg); }
        }
        @keyframes breathe-playful {
          0%, 100% { transform: scale(1); }
          50% { transform: scale(1.03); }
        }
        @keyframes sway-playful {
          0%, 100% { transform: rotate(-1.5deg); }
          50% { transform: rotate(1.5deg); }
        }
        .anim-float {
          transform-origin: center;
          animation: float-playful 5s cubic-bezier(0.25, 1, 0.5, 1) infinite;
        }
        .anim-breathe {
          transform-origin: center;
          animation: breathe-playful 6s cubic-bezier(0.25, 1, 0.5, 1) infinite;
        }
        .anim-sway {
          transform-origin: center;
          animation: sway-playful 6s cubic-bezier(0.25, 1, 0.5, 1) infinite;
        }
      `}</style>
      <g filter="url(#clay-filter)">
        <g transform="translate(2, 2) scale(0.875)">
          {children}
        </g>
      </g>
    </svg>
  );
};

